// يبني طلب Claude لاستخراج ملف منظّم من النص الحر
const b = $json.body || {};
const sys = `أنت محلل سير ذاتية محترف. حوّل نص المستخدم إلى JSON صالح فقط، بدون أي شرح أو نص إضافي.
المفاتيح المطلوبة: name, email, phone, cities, target_titles (مصفوفة), salary, summary, skills (مصفوفة), achievements (مصفوفة), experience (مصفوفة من كائنات {title, org, period, points: مصفوفة}), education, languages.
استخدم المعلومات الواقعية الواردة فقط ولا تختلق أي مهارة أو خبرة. أعد JSON فقط.`;
const story = (b.story || "").toString().trim();
return [{ json: {
  model: "claude-sonnet-4-6",
  max_tokens: 2000,
  system: sys,
  messages: [{ role: "user", content: story || "لا يوجد نص" }]
}}];

// يحوّل مخرجات Claude + بيانات النموذج إلى صفحة Notion في قاعدة المرشحين
let parsed = {};
try {
  const txt = ($json.content && $json.content[0] && $json.content[0].text) ? $json.content[0].text : "{}";
  parsed = JSON.parse(txt.replace(/```json|```/g, "").trim());
} catch (e) { parsed = {}; }

const b = $('استقبال النموذج').item.json.body || {};
const today = new Date().toISOString().slice(0, 10);

function rt(s){ return { rich_text: [{ text: { content: (s || "").toString().slice(0, 1900) } }] }; }

const props = {
  "الاسم": { title: [{ text: { content: (b.name || parsed.name || "بدون اسم").toString() } }] },
  "البريد": { email: (b.email || parsed.email || "") || null },
  "الجوال": { phone_number: (b.phone || parsed.phone || "") || null },
  "المدن": rt(b.cities || parsed.cities),
  "المسميات المستهدفة": rt(Array.isArray(parsed.target_titles) ? parsed.target_titles.join(" · ") : (parsed.target_titles || "")),
  "نطاق الراتب": rt(b.salary || parsed.salary),
  "الكلمات المفتاحية": rt(Array.isArray(parsed.skills) ? parsed.skills.join(", ") : (parsed.skills || "")),
  "لينكدإن": { url: (b.linkedin || "") || null },
  "الحالة": { select: { name: "نشط" } },
  "موافقة على التقديم نيابةً": { checkbox: b.consent === true },
  "تاريخ الموافقة": { date: { start: today } }
};
// إزالة الخصائص الفارغة التي قد ترفضها Notion
if (!props["البريد"].email) delete props["البريد"];
if (!props["الجوال"].phone_number) delete props["الجوال"];
if (!props["لينكدإن"].url) delete props["لينكدإن"];

const children = [];
function h2(t){ children.push({ object:"block", type:"heading_2", heading_2:{ rich_text:[{ text:{ content:t } }] } }); }
function p(t){ children.push({ object:"block", type:"paragraph", paragraph:{ rich_text:[{ text:{ content:(t||"").toString().slice(0,1900) } }] } }); }

if (parsed.summary){ h2("الملخص المهني"); p(parsed.summary); }
if (Array.isArray(parsed.skills) && parsed.skills.length){ h2("المهارات"); p(parsed.skills.join(" · ")); }
if (Array.isArray(parsed.achievements) && parsed.achievements.length){ h2("أبرز الإنجازات"); for (const a of parsed.achievements) p("• " + a); }
if (Array.isArray(parsed.experience) && parsed.experience.length){
  h2("الخبرات");
  for (const e of parsed.experience){
    p(`${e.title || ""} — ${e.org || ""} · ${e.period || ""}`);
    for (const pt of (e.points || [])) p("• " + pt);
  }
}
if (parsed.education){ h2("التعليم"); p(parsed.education); }
if (parsed.languages){ h2("اللغات"); p(Array.isArray(parsed.languages) ? parsed.languages.join(", ") : parsed.languages); }

// Notion يرفض أكثر من 100 كتلة في طلب إنشاء الصفحة
return [{ json: {
  parent: { database_id: "d3168d6642a942d59e0b21c849a8f46d" },
  properties: props,
  children: children.slice(0, 100)
}}];
